function report = runPaperStudyTuning(options)
%RUNPAPERSTUDYTUNING Execute the frozen P2 tuning suite and select policy.
%
% Official tuning cases are rendered once. Primary curves are evaluated for
% every preregistered derivative/integration pair. Widely-linear condition
% limits and complex-log energy percentiles are screened separately. Selection
% uses equal-scene endpoint EPE and the frozen tie rule; dense promotion uses
% true-height percentile rank against each named baseline. Held-out rows are
% never requested. Traceability: algo/main.tex unified experimental program;
% implementation plan P2 step 3; D057--D064.

arguments
    options.StudyFile (1, 1) string = ...
        PaperStudyContract.defaultStudyFile
    options.OutputFile (1, 1) string = ""
    options.FullReportFile (1, 1) string = ""
    options.OutcomeIdentifier (1, 1) string = "paper_study_tuning_v1"
    options.ExistingReportFile (1, 1) string = ""
    options.SourceImplementationCommit (1, 1) string = ""
    options.SourceEvaluationCommit (1, 1) string = ""
    options.WorkingPrecision (1, 1) string ...
        {mustBeMember(options.WorkingPrecision, ...
        ["single", "double"])} = "single"
    options.RetainEvaluations (1, 1) logical = true
    options.Verbose (1, 1) logical = true
end

root = fileparts(fileparts(mfilename("fullpath")));
oldPath = path;
addpath(fullfile(root, "src"));
cleanup = onCleanup(@() path(oldPath));
contract = PaperStudyContract(options.StudyFile);
if ~ismember(contract.State, ...
        ["preregistered-unrun", "tuning-complete", "tuning-invalid"])
    error("runPaperStudyTuning:StateDisallowsTuning", ...
        "Tuning cannot run from manifest state '%s'.", contract.State);
end
s = contract.Manifest;
cases = contract.tuningCases;
settings = scaleSettings(s.tunablePolicy);
evaluator = PaperStudySparseEvaluator(s);
nc = height(cases);
ns = height(settings);
primaryPart = cell(nc .* ns, 1);
diagnosticPerScale = numel( ...
    s.tunablePolicy.widelyLinearConditionLimit) + numel( ...
    s.tunablePolicy.complexLogGradientEnergyPercentile);
diagnosticPart = cell(nc .* ns .* diagnosticPerScale, 1);
diagnosticCount = 0;
if options.RetainEvaluations
    primaryEvaluation = cell(nc, ns);
    diagnosticEvaluation = cell(nc, ns);
else
    primaryEvaluation = cell(0);
    diagnosticEvaluation = cell(0);
end

totalTimer = tic;
reaggregated = options.ExistingReportFile ~= "";
if reaggregated
    loaded = load(options.ExistingReportFile, "report");
    prior = loaded.report;
    if prior.HeldoutAccessed ...
            || prior.StudyIdentifier ~= contract.Identifier ...
            || ~isequal(string(prior.CaseIdentifiers(:)), ...
            cases.Identifier)
        error("runPaperStudyTuning:InvalidExistingReport", ...
            "Existing report does not match the locked tuning-only plan.");
    end
    primary = prior.PrimaryResults;
    diagnostic = prior.DiagnosticResults;
    evaluationSeconds = prior.TotalSeconds;
    if options.RetainEvaluations
        primaryEvaluation = prior.Evaluations.Primary;
        diagnosticEvaluation = prior.Evaluations.Diagnostic;
    end
else
for i = 1:nc
    if options.Verbose
        fprintf("P2 tuning render %d/%d: %s\n", ...
            i, nc, cases.Identifier(i));
    end
    rendered = PaperStudySyntheticCase( ...
        cases(i, :), s).render( ...
        WorkingPrecision=options.WorkingPrecision);
    for j = 1:ns
        ds = settings.DerivativeSigma(j);
        is = settings.IntegrationSigma(j);
        if options.Verbose
            fprintf("  scale %d/%d: derivative %.3g, integration %.3g\n", ...
                j, ns, ds, is);
        end
        q = evaluator.evaluate(rendered, ...
            DerivativeSigma=ds, IntegrationSigma=is);
        t = q.Summary;
        t.Case = repmat(cases.Identifier(i), height(t), 1);
        t.SettingIdentifier = repmat( ...
            settings.SettingIdentifier(j), height(t), 1);
        t.DerivativeSigma = repmat(ds, height(t), 1);
        t.IntegrationSigma = repmat(is, height(t), 1);
        t.AuxiliarySettingName = repmat("", height(t), 1);
        t.AuxiliarySettingValue = nan(height(t), 1);
        t.SharedSeconds = repmat( ...
            q.EvaluationSeconds.Total, height(t), 1);
        primaryPart{(i - 1) .* ns + j} = t;
        if options.RetainEvaluations
            primaryEvaluation{i, j} = q;
        end

        maximumCondition = max(double( ...
            s.tunablePolicy.widelyLinearConditionLimit));
        wd = evaluator.evaluateDiagnostics(rendered, ...
            DerivativeSigma=ds, IntegrationSigma=is, ...
            MaximumConditionNumber=maximumCondition, ...
            IncludeWidelyLinear=true, IncludeComplexLog=false);
        wl = wd.WidelyLinearResidual.Curve;
        condition = double( ...
            s.tunablePolicy.widelyLinearConditionLimit(:));
        for c = condition.'
            filtered = filterWidelyLinear(wl, c);
            diagnosticCount = diagnosticCount + 1;
            diagnosticPart{diagnosticCount} = diagnosticRow( ...
                "WidelyLinearResidual", ...
                string(s.tunablePolicy.diagnosticSelectionCurves. ...
                WidelyLinearResidual), filtered, rendered, ...
                settings(j, :), "MaximumConditionNumber", c, ...
                wd.EvaluationSeconds.WidelyLinear);
        end

        percentile = double( ...
            s.tunablePolicy.complexLogGradientEnergyPercentile(:));
        logs = cell(numel(percentile), 1);
        for k = 1:numel(percentile)
            ld = evaluator.evaluateDiagnostics(rendered, ...
                DerivativeSigma=ds, IntegrationSigma=is, ...
                GradientEnergyPercentile=percentile(k), ...
                IncludeWidelyLinear=false, IncludeComplexLog=true);
            logCurve = ld.ComplexLogResidual.Curve;
            diagnosticCount = diagnosticCount + 1;
            diagnosticPart{diagnosticCount} = diagnosticRow( ...
                "ComplexLogResidual", ...
                string(s.tunablePolicy.diagnosticSelectionCurves. ...
                ComplexLogResidual), logCurve, rendered, ...
                settings(j, :), "GradientEnergyPercentile", ...
                percentile(k), ld.EvaluationSeconds.ComplexLog);
            if options.RetainEvaluations
                logs{k} = ld;
            end
        end
        if options.RetainEvaluations
            diagnosticEvaluation{i, j} = struct( ...
                "WidelyLinearMaximumCondition", wd, ...
                "ComplexLogByPercentile", {logs});
        end
    end
end
primary = vertcat(primaryPart{:});
diagnostic = vertcat(diagnosticPart{1:diagnosticCount});
evaluationSeconds = toc(totalTimer);
end
selectionTimer = tic;
primaryEvidence = aggregateEvidence( ...
    primary, string(s.methods.primaryMatching(:)));
primarySelection = selectSettings(primaryEvidence);
diagnosticEvidence = aggregateEvidence( ...
    diagnostic, string(s.methods.diagnosticOnly(1:2)));
diagnosticSelection = selectSettings(diagnosticEvidence);
[promotionEvidence, promoted] = promoteCandidates( ...
    primarySelection, s.methods.denseCandidateScreen);
gate = chooseHarmonicGate(primarySelection);
denseMethods = unique([string(s.methods.denseMandatory(:)); ...
    promoted(:)], "stable");
policy = struct( ...
    "PrimarySettings", table2struct(primarySelection), ...
    "DiagnosticSettings", table2struct(diagnosticSelection), ...
    "SelectedMultiHarmonicGate", gate, ...
    "PromotedDenseCandidates", promoted(:).', ...
    "DenseMethods", denseMethods(:).', ...
    "SelectionRule", string(s.tunablePolicy.selectionRule), ...
    "HeldoutAccessedAtFreeze", false, ...
    "AppliedWithoutOverride", true, ...
    "SourceEvaluationCommit", ...
    options.SourceEvaluationCommit, ...
    "SourceImplementationCommit", ...
    options.SourceImplementationCommit);
summary = struct( ...
    "identifier", options.OutcomeIdentifier, ...
    "sourceStudyIdentifier", contract.Identifier, ...
    "state", "tuning-complete", ...
    "tuningCaseIdentifiers", cases.Identifier.', ...
    "heldoutAccessed", false, ...
    "valid", true, ...
    "reaggregatedFromExistingEvidence", reaggregated, ...
    "primarySettingEvidence", table2struct(primaryEvidence), ...
    "diagnosticSettingEvidence", table2struct(diagnosticEvidence), ...
    "densePromotionEvidence", table2struct(promotionEvidence), ...
    "policyCandidate", policy);
report = struct( ...
    "Mode", "tuning", ...
    "StudyIdentifier", contract.Identifier, ...
    "StudyState", contract.State, ...
    "CaseIdentifiers", cases.Identifier.', ...
    "ScaleSettings", settings, ...
    "PrimaryResults", primary, ...
    "DiagnosticResults", diagnostic, ...
    "PrimarySettingEvidence", primaryEvidence, ...
    "PrimarySelection", primarySelection, ...
    "DiagnosticSettingEvidence", diagnosticEvidence, ...
    "DiagnosticSelection", diagnosticSelection, ...
    "DensePromotionEvidence", promotionEvidence, ...
    "PolicyCandidate", policy, ...
    "Evaluations", struct( ...
    "Retained", options.RetainEvaluations, ...
    "Primary", {primaryEvaluation}, ...
    "Diagnostic", {diagnosticEvaluation}), ...
    "HeldoutAccessed", false, ...
    "ReaggregatedFromExistingEvidence", reaggregated, ...
    "EvaluationSeconds", evaluationSeconds, ...
    "AggregationSeconds", toc(selectionTimer), ...
    "TotalSeconds", evaluationSeconds, ...
    "SummaryArtifact", summary);
if options.OutputFile ~= ""
    writelines(jsonencode(summary, PrettyPrint=true), options.OutputFile);
end
if options.FullReportFile ~= ""
    save(options.FullReportFile, "report", "-v7.3");
end
if options.Verbose
    if reaggregated
        fprintf("P2 tuning evidence reaggregated: %d cases, " ...
            + "held-out accessed: false\n", nc);
    else
        fprintf("P2 tuning complete: %d cases, %.3f s, " ...
            + "held-out accessed: false\n", nc, report.TotalSeconds);
    end
    disp(primarySelection(:, ["Method", "DerivativeSigma", ...
        "IntegrationSigma", "MeanSceneEndpointEpeRmsePixels"]));
    disp(diagnosticSelection(:, ["Method", "DerivativeSigma", ...
        "IntegrationSigma", "AuxiliarySettingName", ...
        "AuxiliarySettingValue", "MeanSceneEndpointEpeRmsePixels"]));
    disp(promotionEvidence)
end
clear cleanup
end

function settings = scaleSettings(policy)
d = double(policy.derivativeSigmaPixels(:));
i = double(policy.integrationSigmaPixels(:));
[dd, ii] = ndgrid(d, i);
dd = dd(:);
ii = ii(:);
id = strings(numel(dd), 1);
for k = 1:numel(dd)
    id(k) = compose("d%.3g_i%.3g", dd(k), ii(k));
end
settings = table(id, dd, ii, VariableNames=[ ...
    "SettingIdentifier", "DerivativeSigma", "IntegrationSigma"]);
end

function out = filterWidelyLinear(in, limit)
out = in;
fit = in.FitValid & in.ConditionNumber <= limit;
names = string(fieldnames(in.Costs));
for name = names.'
    c = out.Costs.(name);
    c(~fit) = NaN;
    out.Costs.(name) = c;
    out.Valid.(name) = isfinite(c);
    out.SelectedHeight.(name) = selectHeight(c, out.Height);
end
out.FitValid = fit;
end

function row = diagnosticRow(method, curveName, curve, rendered, ...
        setting, auxiliaryName, auxiliaryValue, seconds)
use = rendered.TruthValid;
p = rendered.SamplePixelXY(use, :);
truthHeight = rendered.TruthHeightMetres(use);
truthCorrespondence = rendered.TruthCorrespondenceXY(use, :);
metric = HeightCostMetrics.analyze(curve, truthHeight);
m = metric.(curveName);
selected = m.SelectedHeightMetres;
geometry = HeightSweepGeometry( ...
    rendered.ReferenceCamera, rendered.MatchingMovingCamera);
w = nan(size(p));
valid = false(size(selected));
q = isfinite(selected);
if any(q)
    [w(q, :), valid(q)] = geometry.warp(p(q, :), selected(q));
end
e = vecnorm(w - truthCorrespondence, 2, 2);
e(~valid) = NaN;
rmse = finiteRms(e);
row = table(method, rendered.Identifier, setting.SettingIdentifier, ...
    setting.DerivativeSigma, setting.IntegrationSigma, ...
    auxiliaryName, auxiliaryValue, nnz(use), mean(valid), rmse, ...
    finitePercentile(e, 50), finitePercentile(e, 90), ...
    finitePercentile(e, 95), ...
    mean(abs(m.SelectedHeightErrorMetres), "omitnan"), ...
    finiteRms(m.SelectedHeightErrorMetres), ...
    mean(m.TruthCostPercentile, "omitnan"), ...
    mean(m.IsUniqueTruthBest, "omitnan"), seconds, ...
    VariableNames=["Method", "Case", "SettingIdentifier", ...
    "DerivativeSigma", "IntegrationSigma", ...
    "AuxiliarySettingName", "AuxiliarySettingValue", "SampleCount", ...
    "EndpointCoverage", "EndpointEpeRmsePixels", ...
    "EndpointEpeP50Pixels", "EndpointEpeP90Pixels", ...
    "EndpointEpeP95Pixels", "HeightMaeMetres", ...
    "HeightRmseMetres", "MeanTruthCostPercentile", ...
    "UniqueTruthBestFraction", "SharedSeconds"]);
end

function evidence = aggregateEvidence(results, methods)
rows = cell(0, 12);
r = 0;
for method = methods.'
    m = results(results.Method == method, :);
    key = m.SettingIdentifier + "|" + m.AuxiliarySettingName ...
        + "|" + compose("%.17g", m.AuxiliarySettingValue);
    ids = unique(key, "stable");
    for id = ids.'
        q = m(key == id, :);
        if isempty(q)
            error("runPaperStudyTuning:EmptyEvidenceGroup", ...
                "Empty evidence group for method %s and key %s.", ...
                method, id);
        end
        r = r + 1;
        rows(r, :) = {method, q.SettingIdentifier(1), ...
            q.DerivativeSigma(1), ...
            q.IntegrationSigma(1), q.AuxiliarySettingName(1), ...
            q.AuxiliarySettingValue(1), height(q), ...
            completeMean(q.EndpointEpeRmsePixels), ...
            mean(q.EndpointCoverage, "omitnan"), ...
            completeMean(q.MeanTruthCostPercentile), ...
            mean(q.UniqueTruthBestFraction, "omitnan"), ...
            sum(q.SharedSeconds, "omitnan")};
    end
end
evidence = cell2table(rows, VariableNames=[ ...
    "Method", "SettingIdentifier", "DerivativeSigma", ...
    "IntegrationSigma", "AuxiliarySettingName", ...
    "AuxiliarySettingValue", "SceneCount", ...
    "MeanSceneEndpointEpeRmsePixels", "MeanEndpointCoverage", ...
    "MeanSceneTruthCostPercentile", "MeanUniqueTruthBestFraction", ...
    "TotalSeconds"]);
end

function selected = selectSettings(evidence)
methods = unique(evidence.Method, "stable");
parts = cell(numel(methods), 1);
for k = 1:numel(methods)
    q = evidence(evidence.Method == methods(k), :);
    best = min(q.MeanSceneEndpointEpeRmsePixels);
    if isinf(best)
        near = true(height(q), 1);
    else
        near = q.MeanSceneEndpointEpeRmsePixels <= best + 0.01;
    end
    q = q(near, :);
    q = sortrows(q, ["TotalSeconds", "IntegrationSigma", ...
        "DerivativeSigma", "AuxiliarySettingValue"], ...
        ["ascend", "ascend", "ascend", "ascend"]);
    parts{k} = q(1, :);
end
selected = vertcat(parts{:});
end

function [evidence, promoted] = promoteCandidates(selection, screen)
map = screen.baselineByCandidate;
rows = cell(numel(map), 6);
for k = 1:numel(map)
    candidate = string(map(k).candidate);
    baseline = string(map(k).baseline);
    c = selection(selection.Method == candidate, :);
    b = selection(selection.Method == baseline, :);
    cp = c.MeanSceneTruthCostPercentile;
    bp = b.MeanSceneTruthCostPercentile;
    improvement = 0;
    if isfinite(bp) && bp > eps
        improvement = (bp - cp) ./ bp;
    end
    pass = isfinite(improvement) ...
        && improvement >= screen.minimumRelativeImprovement;
    rows(k, :) = {candidate, baseline, cp, bp, improvement, pass};
end
evidence = cell2table(rows, VariableNames=[ ...
    "Candidate", "Baseline", "CandidateMeanTruthCostPercentile", ...
    "BaselineMeanTruthCostPercentile", "RelativeImprovement", "Passed"]);
pass = evidence(evidence.Passed, :);
pass = sortrows(pass, ["RelativeImprovement", "Candidate"], ...
    ["descend", "ascend"]);
n = min(height(pass), screen.maximumPromotedCandidates);
promoted = pass.Candidate(1:n);
end

function gate = chooseHarmonicGate(selection)
q = selection(ismember(selection.Method, ...
    ["MultiHarmonicFixed", "MultiHarmonicGated"]), :);
best = min(q.MeanSceneEndpointEpeRmsePixels);
q = q(q.MeanSceneEndpointEpeRmsePixels <= best + 0.01, :);
q = sortrows(q, ["TotalSeconds", "IntegrationSigma", ...
    "DerivativeSigma", "Method"], ...
    ["ascend", "ascend", "ascend", "ascend"]);
if q.Method(1) == "MultiHarmonicGated"
    gate = "hand-gated";
else
    gate = "fixed";
end
end

function z = selectHeight(cost, labels)
[~, k] = min(cost, [], 2, "omitnan");
z = reshape(labels(k), [], 1);
z(all(~isfinite(cost), 2)) = NaN;
end

function y = completeMean(x)
if all(isfinite(x))
    y = mean(x);
else
    y = Inf;
end
end

function y = finiteRms(x)
x = x(isfinite(x));
if isempty(x)
    y = NaN;
else
    y = sqrt(mean(x .^ 2));
end
end

function y = finitePercentile(x, q)
x = sort(x(isfinite(x)));
if isempty(x)
    y = NaN;
    return
end
k = 1 + (numel(x) - 1) .* q ./ 100;
lo = floor(k);
hi = ceil(k);
y = x(lo) + (k - lo) .* (x(hi) - x(lo));
end
